mapper.update:
update chat_viewable_teams
set is_active = true
where user_id = #{userId}
  and corp_code = #{corpCode}
  and dept_code = #{deptCode}
  and is_deleted = false

update chat_viewable_teams
set conversations = case
    when #{conversationId} = any (conversations) then conversations
    else array_append(conversations, #{conversationId})
end
where user_id = #{userId}
  and corp_code = #{corpCode}
  and dept_code = #{deptCode}
  and is_deleted = false

update chat_viewable_teams
set conversations = coalesce(
    array(
        select e
        from unnest(conversations) as e
        where e not in

            #{id}

    ),
    '{}'::integer[]
)
where user_id = #{userId}
  and is_deleted = false
